import React, { useState, useEffect } from "react";
import Map from "./Map";
import axios from "../api";
import "./SearchForm.css";

const SearchForm = () => {
  const [districts, setDistricts] = useState([]);
  const [talukas, setTalukas] = useState([]);
  const [villages, setVillages] = useState([]);
  const [recordType, setRecordType] = useState("7/12");
  const [searchBy, setSearchBy] = useState("survey");

  const [formData, setFormData] = useState({
    district: "",
    taluka: "",
    village: "",
    survey_number: "",
    part_number: "",
    name: "",
    mobile: "",
    captcha: ""
  });

  // Fetch districts
  useEffect(() => {
    axios.get("/districts/").then(res => setDistricts(res.data));
  }, []);

  // Fetch talukas when district changes
  useEffect(() => {
    if (formData.district) {
      axios.get(`/talukas/${formData.district}/`).then(res => setTalukas(res.data));
      setFormData({ ...formData, taluka: "", village: "" });
      setVillages([]);
    }
  }, [formData.district]);

  // Fetch villages when taluka changes
  useEffect(() => {
    if (formData.taluka) {
      axios.get(`/villages/${formData.taluka}/`).then(res => setVillages(res.data));
      setFormData({ ...formData, village: "" });
    }
  }, [formData.taluka]);

  const handleDistrictClick = (districtName) => {
    const districtObj = districts.find(d => d.name === districtName);
    if (districtObj) setFormData({ ...formData, district: districtObj.id });
  };

  const handleChange = e => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = e => {
    e.preventDefault();
    const payload = { ...formData, record_type: recordType, search_by: searchBy };
    axios.post("/search/", payload).then(res => {
      console.log(res.data);
    });
  };

  const handleReset = () => {
    setFormData({
      district: "",
      taluka: "",
      village: "",
      survey_number: "",
      part_number: "",
      name: "",
      mobile: "",
      captcha: ""
    });
    setRecordType("7/12");
    setSearchBy("survey");
  };

  return (
    <div className="search-layout">
      <div className="map-section">
        <h3>Maharashtra District Map</h3>
        <Map onDistrictClick={handleDistrictClick} />
      </div>

      <div className="form-section">
        <h3>भूलेख / Land Record Search</h3>

        {/* Record type */}
        <div className="record-type">
          {["7/12","8A","PropertyCard","KPrat"].map(rt => (
            <label key={rt}>
              <input type="radio" value={rt} checked={recordType===rt} onChange={()=>setRecordType(rt)} /> {rt}
            </label>
          ))}
        </div>

        {/* Search form */}
        <form onSubmit={handleSubmit}>
          <label>District</label>
          <select name="district" value={formData.district} onChange={handleChange}>
            <option value="">--Select--</option>
            {districts.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
          </select>

          <label>Taluka</label>
          <select name="taluka" value={formData.taluka} onChange={handleChange}>
            <option value="">--Select--</option>
            {talukas.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
          </select>

          <label>Village</label>
          <select name="village" value={formData.village} onChange={handleChange}>
            <option value="">--Select--</option>
            {villages.map(v => <option key={v.id} value={v.id}>{v.name}</option>)}
          </select>

          {/* Search by toggle */}
          <div className="search-by">
            <label><input type="radio" checked={searchBy==="survey"} onChange={()=>setSearchBy("survey")} /> Survey/Gat Number</label>
            <label><input type="radio" checked={searchBy==="name"} onChange={()=>setSearchBy("name")} /> Name</label>
          </div>

          {searchBy==="survey" && (
            <>
              <label>Survey Number</label>
              <input type="text" name="survey_number" value={formData.survey_number} onChange={handleChange} />

              <label>Part Number</label>
              <input type="text" name="part_number" value={formData.part_number} onChange={handleChange} />
            </>
          )}

          {searchBy==="name" && (
            <>
              <label>Name</label>
              <input type="text" name="name" value={formData.name} onChange={handleChange} />
            </>
          )}

          <label>Mobile</label>
          <input type="text" name="mobile" value={formData.mobile} onChange={handleChange} />

          <label>Captcha</label>
          <input type="text" name="captcha" value={formData.captcha} onChange={handleChange} />
          <img src="/captcha-image/" alt="captcha" />

          <div className="form-buttons">
            <button type="submit">Submit</button>
            <button type="button" onClick={handleReset}>Reset</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default SearchForm;
